#include <print>
#include <vector>
#include <stdexcept>
#include <cstddef>

// Динамическая 2D-сетка — тот же паттерн, что использует std::mdspan:
// одномерное хранилище + вычисление плоского индекса в operator[]
struct Grid {
    size_t rows, cols;
    std::vector<double> data;

    Grid(size_t r, size_t c) : rows(r), cols(c), data(r * c, 0.0) {}

    double& operator[](size_t i, size_t j) {
        if (i >= rows || j >= cols) throw std::out_of_range("Grid: index out of range");
        return data[i * cols + j];
    }

    double operator[](size_t i, size_t j) const {
        if (i >= rows || j >= cols) throw std::out_of_range("Grid: index out of range");
        return data[i * cols + j];
    }
};

int main() {
    Grid g{3, 4};
    g[0, 0] = 1.0;
    g[1, 2] = 5.0;
    g[2, 3] = 9.0;

    std::println("g[0,0] = {:.0f}", g[0, 0]);
    std::println("g[1,2] = {:.0f}", g[1, 2]);
    std::println("g[2,3] = {:.0f}", g[2, 3]);
    std::println("g[0,1] = {:.0f}", g[0, 1]);

    try {
        [[maybe_unused]] double x = g[5, 0]; // выход за границы
    } catch (const std::out_of_range& e) {
        std::println("caught: {}", e.what());
    }
}

#include <print>
#include <string>
#include <vector>

int main() {
    // 1. Базовое decay-копирование: снимаем ссылочность и cv-квалификаторы
    std::string original = "hello";
    const std::string& ref = original;
    auto copy = auto(ref);  // copy — это std::string, а не const std::string&
    std::println("copy: {}", copy);

    // 2. Захват в лямбде — безопасная копия ссылки
    std::string msg = "world";
    auto printer = [captured = auto(msg)] {
        std::println("captured: {}", captured);
    };
    msg = "changed";
    printer();  // выводит "world", а не "changed"

    // 3. auto{x} — эквивалентная форма с фигурными скобками
    int arr[3] = {1, 2, 3};
    auto* ptr = auto(arr);  // decay массива в указатель
    std::println("ptr[0]: {}", ptr[0]);
}

#include <print>

int main() {
    int value = 10;

    // C++23: mutable-лямбда без () — захват по значению, изменяет копию
    auto increment = [value] mutable {
        ++value;
        std::println("inside: {}", value);
    };
    increment();  // inside: 11
    increment();  // inside: 12
    std::println("outside: {}", value);  // не изменилось: 10

    // C++23: trailing return type без ()
    auto to_long = [] -> long long { return 1'000'000'000LL * 3; };
    std::println("to_long: {}", to_long());

    // C++23: noexcept без ()
    auto safe_neg = [](int n) noexcept { return -n; };
    std::println("safe_neg(7): {}", safe_neg(7));

    // C++23: constexpr без ()
    auto pi_approx = [] constexpr { return 3.14159; };
    std::println("pi: {}", pi_approx());
}

